    public Object handleOHLCV(Client client, Object message)
    {
        //
        //    {
        //        "channel": "candles_minute_1",
        //        "data": [
        //            {
        //                "symbol": "BTC_USDT",
        //                "amount": "840.7240416",
        //                "high": "24832.35",
        //                "quantity": "0.033856",
        //                "tradeCount": 1,
        //                "low": "24832.35",
        //                "closeTime": 1676942519999,
        //                "startTime": 1676942460000,
        //                "close": "24832.35",
        //                "open": "24832.35",
        //                "ts": 1676942492072
        //            }
        //        ]
        //    }
        //
        Object data = this.safeValue(message, "data");
        data = this.safeValue(data, 0);
        Object channel = this.safeString(message, "channel");
        Object marketId = this.safeString(data, "symbol");
        Object symbol = this.safeSymbol(marketId);
        Object market = this.safeMarket(symbol);
        Object timeframes = this.safeValue(this.options, "timeframes", new java.util.HashMap<String, Object>() {{}});
        Object timeframe = this.findTimeframe(channel, timeframes);
        Object messageHash = Helpers.add(Helpers.add(channel, "::"), symbol);
        Object parsed = this.parseWsOHLCV(data, market);
        Helpers.addElementToObject(this.ohlcvs, symbol, this.safeValue(this.ohlcvs, symbol, new java.util.HashMap<String, Object>() {{}}));
        Object stored = ((Helpers.isTrue((Helpers.isEqual(timeframe, null))))) ? null : this.safeValue(Helpers.GetValue(this.ohlcvs, symbol), timeframe);
        if (Helpers.isTrue(!Helpers.isEqual(symbol, null)))
        {
            if (Helpers.isTrue(Helpers.isEqual(stored, null)))
            {
                Object limit = this.safeInteger(this.options, "OHLCVLimit", 1000);
                stored = new ArrayCache.ArrayCacheByTimestamp(((Number)limit).intValue());
                Helpers.addElementToObject(Helpers.GetValue(this.ohlcvs, symbol), timeframe, stored);
            }
            Helpers.callDynamically(stored, "append", new Object[]{parsed});
            client.resolve(stored, messageHash);
        }
        return message;
    }

